insert into public.about_page ("id", "title", "summary", "sections", "date_updated")
values
  (1, 'Rebase 是一个围绕 builder、community operator 和研究者展开的社区媒体网络。', '我们把社区里的文章、GeekDaily、活动、招聘和贡献者信息放在同一个公共空间里，让信息流动更连续，也让参与路径更清晰。', '[{"title":"Why Rebase","body":"当社区信息散落在 issue、表单、微信群、社交媒体和一篇篇临时帖子里，很多有价值的内容很容易被时间冲淡。Rebase 想把这些信号整理成更容易浏览、检索和订阅的公共媒介。"},{"title":"What we organize","body":"我们会持续组织 GeekDaily、社区文章、Who-Is-Hiring、线下或线上活动，以及贡献者故事。它们不应该是彼此孤立的栏目，而应该共同构成社区的长期记录。"},{"title":"How people participate","body":"你可以投稿文章、发布招聘、参与活动、加入志愿协作，或者成为 GeekDaily 智囊团的一部分。这个网站会尽量把每一种参与方式都表达得更直接。"}]'::jsonb, '2026-04-05T10:00:00.000Z')
on conflict do nothing;

